import{_ as t,c as i,o,ax as a}from"./chunks/framework.DHqKNX4U.js";const p=JSON.parse('{"title":"Retention Policy: User Interface","description":"","frontmatter":{},"headers":[],"relativePath":"enterprise/retention-policy/guide.md","filePath":"enterprise/retention-policy/guide.md"}'),n={name:"enterprise/retention-policy/guide.md"};function r(s,e,l,c,d,h){return o(),i("div",null,e[0]||(e[0]=[a('<h1 id="retention-policy-user-interface" tabindex="-1">Retention Policy: User Interface <a class="header-anchor" href="#retention-policy-user-interface" aria-label="Permalink to &quot;Retention Policy: User Interface&quot;">​</a></h1><p>The retention policy management interface is located at <strong>Dashboard → Compliance → Retention Policies</strong>. It provides a comprehensive view of all configured policies and tools for creating, editing, deleting, and simulating retention rules.</p><h2 id="policy-table" tabindex="-1">Policy Table <a class="header-anchor" href="#policy-table" aria-label="Permalink to &quot;Policy Table&quot;">​</a></h2><p>The main page displays a table of all retention policies with the following columns:</p><ul><li><strong>Name:</strong> The policy name and its UUID displayed underneath for reference.</li><li><strong>Priority:</strong> The numeric priority value. Lower values indicate higher priority.</li><li><strong>Retention Period:</strong> The number of days emails matching this policy are retained before expiry.</li><li><strong>Ingestion Scope:</strong> Shows which ingestion sources the policy is restricted to. Displays &quot;All ingestion sources&quot; when the policy has no scope restriction, or individual source name badges when scoped.</li><li><strong>Conditions:</strong> A summary of the rule group. Displays &quot;No conditions (matches all emails)&quot; for policies without conditions, or &quot;N rule(s) (AND/OR)&quot; for policies with conditions.</li><li><strong>Status:</strong> A badge indicating whether the policy is Active or Inactive.</li><li><strong>Actions:</strong> Edit and Delete buttons for each policy.</li></ul><p>The table is sorted by policy priority by default.</p><h2 id="creating-a-policy" tabindex="-1">Creating a Policy <a class="header-anchor" href="#creating-a-policy" aria-label="Permalink to &quot;Creating a Policy&quot;">​</a></h2><p>Click the <strong>&quot;Create Policy&quot;</strong> button above the table to open the creation dialog. The form contains the following sections:</p><h3 id="basic-information" tabindex="-1">Basic Information <a class="header-anchor" href="#basic-information" aria-label="Permalink to &quot;Basic Information&quot;">​</a></h3><ul><li><strong>Policy Name:</strong> A unique, descriptive name for the policy.</li><li><strong>Description:</strong> An optional detailed description of the policy&#39;s purpose.</li><li><strong>Priority:</strong> A positive integer determining evaluation order (lower = higher priority).</li><li><strong>Retention Period (Days):</strong> The number of days to retain matching emails.</li></ul><h3 id="ingestion-scope" tabindex="-1">Ingestion Scope <a class="header-anchor" href="#ingestion-scope" aria-label="Permalink to &quot;Ingestion Scope&quot;">​</a></h3><p>This section controls which ingestion sources the policy applies to:</p><ul><li><strong>&quot;All ingestion sources&quot; toggle:</strong> When enabled, the policy applies to emails from all ingestion sources. This is the default.</li><li><strong>Per-source checkboxes:</strong> When the &quot;all&quot; toggle is disabled, individual ingestion sources can be selected. Each source displays its name and provider type as a badge.</li></ul><h3 id="condition-rules" tabindex="-1">Condition Rules <a class="header-anchor" href="#condition-rules" aria-label="Permalink to &quot;Condition Rules&quot;">​</a></h3><p>Conditions define which emails the policy targets. If no conditions are added, the policy matches all emails (within its ingestion scope).</p><ul><li><strong>Logical Operator:</strong> Choose <strong>AND</strong> (all rules must match) or <strong>OR</strong> (any rule must match).</li><li><strong>Add Rule:</strong> Each rule consists of: <ul><li><strong>Field:</strong> The email metadata field to evaluate (<code>sender</code>, <code>recipient</code>, <code>subject</code>, or <code>attachment_type</code>).</li><li><strong>Operator:</strong> The comparison operator (see <a href="#supported-operators">Supported Operators</a> below).</li><li><strong>Value:</strong> The string value to compare against.</li></ul></li><li><strong>Remove Rule:</strong> Each rule has a remove button to delete it from the group.</li></ul><h3 id="supported-operators" tabindex="-1">Supported Operators <a class="header-anchor" href="#supported-operators" aria-label="Permalink to &quot;Supported Operators&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Operator</th><th>Display Name</th><th>Description</th></tr></thead><tbody><tr><td><code>equals</code></td><td>Equals</td><td>Exact case-insensitive match.</td></tr><tr><td><code>not_equals</code></td><td>Not Equals</td><td>Inverse of equals.</td></tr><tr><td><code>contains</code></td><td>Contains</td><td>Case-insensitive substring match.</td></tr><tr><td><code>not_contains</code></td><td>Not Contains</td><td>Inverse of contains.</td></tr><tr><td><code>starts_with</code></td><td>Starts With</td><td>Case-insensitive prefix match.</td></tr><tr><td><code>ends_with</code></td><td>Ends With</td><td>Case-insensitive suffix match.</td></tr><tr><td><code>domain_match</code></td><td>Domain Match</td><td>Matches when an email address ends with <code>@&lt;value&gt;</code>.</td></tr><tr><td><code>regex_match</code></td><td>Regex Match</td><td>ECMAScript regular expression (case-insensitive, max 200 chars).</td></tr></tbody></table><h3 id="policy-status" tabindex="-1">Policy Status <a class="header-anchor" href="#policy-status" aria-label="Permalink to &quot;Policy Status&quot;">​</a></h3><ul><li><strong>Enable Policy toggle:</strong> Controls whether the policy is active immediately upon creation.</li></ul><h2 id="editing-a-policy" tabindex="-1">Editing a Policy <a class="header-anchor" href="#editing-a-policy" aria-label="Permalink to &quot;Editing a Policy&quot;">​</a></h2><p>Click the <strong>Edit</strong> button (pencil icon) on any policy row to open the edit dialog. The form is pre-populated with the policy&#39;s current values. All fields can be modified, and the same validation rules apply as during creation.</p><h2 id="deleting-a-policy" tabindex="-1">Deleting a Policy <a class="header-anchor" href="#deleting-a-policy" aria-label="Permalink to &quot;Deleting a Policy&quot;">​</a></h2><p>Click the <strong>Delete</strong> button (trash icon) on any policy row. A confirmation dialog appears to prevent accidental deletion. Deleting a policy is irreversible. Once deleted, the policy no longer affects the lifecycle worker&#39;s evaluation of emails.</p><h2 id="policy-simulator" tabindex="-1">Policy Simulator <a class="header-anchor" href="#policy-simulator" aria-label="Permalink to &quot;Policy Simulator&quot;">​</a></h2><p>The <strong>&quot;Simulate Policy&quot;</strong> button opens a simulation tool that evaluates hypothetical email metadata against all active policies without making any changes.</p><h3 id="simulator-input-fields" tabindex="-1">Simulator Input Fields <a class="header-anchor" href="#simulator-input-fields" aria-label="Permalink to &quot;Simulator Input Fields&quot;">​</a></h3><ul><li><strong>Sender Email:</strong> The sender address to evaluate (e.g., <code>cfo@finance.acme.com</code>).</li><li><strong>Recipients:</strong> A comma-separated list of recipient email addresses.</li><li><strong>Subject:</strong> The email subject line.</li><li><strong>Attachment Types:</strong> A comma-separated list of file extensions (e.g., <code>.pdf, .xlsx</code>).</li><li><strong>Ingestion Source:</strong> An optional dropdown to select a specific ingestion source for scope-aware evaluation. Defaults to &quot;All sources&quot;.</li></ul><h3 id="simulator-results" tabindex="-1">Simulator Results <a class="header-anchor" href="#simulator-results" aria-label="Permalink to &quot;Simulator Results&quot;">​</a></h3><p>After submission, the simulator displays:</p><ul><li><strong>Applied Retention Period:</strong> The longest retention period from all matching policies, displayed in days.</li><li><strong>Action on Expiry:</strong> The action that would be taken when the retention period expires (currently always &quot;Permanent Deletion&quot;).</li><li><strong>Matching Policies:</strong> A list of all policy IDs (with their names) that matched the provided metadata. If no policies match, a message indicates that no matching policies were found.</li></ul><p>The simulator is a safe, read-only tool intended for testing and verifying policy configurations before they affect live data.</p>',32)]))}const g=t(n,[["render",r]]);export{p as __pageData,g as default};
